// Extraire BC et analyser pièces jointes
const subject = $input.item.json.subject || '';
const body = $input.item.json.text || $input.item.json.html || '';
const from = $input.item.json.from?.address || '';

// Regex BC
const bcRegex = /BC\d{6}/gi;
let bcMatch = subject.match(bcRegex);
if (!bcMatch) {
  bcMatch = body.match(bcRegex);
}

const numero_bc = bcMatch ? bcMatch[0] : null;

// Analyser pièces jointes depuis binary (objet, pas array)
const binaryData = $input.item.binary || {};
const attachmentKeys = Object.keys(binaryData);

// Construire array d'attachments
const attachments = attachmentKeys.map(key => {
  const att = binaryData[key];
  return {
    key: key,
    filename: att.fileName || key,
    mimeType: att.mimeType || '',
    fileExtension: att.fileExtension || '',
    data: key
  };
});

// Filtrer les PDFs
const pdfAttachments = attachments.filter(att => 
  att.mimeType?.includes('pdf') || 
  att.filename?.toLowerCase().endsWith('.pdf') ||
  att.fileExtension?.toLowerCase() === 'pdf'
);

// IMPORTANT : Retourner avec le binary préservé
return {
  json: {
    numero_bc: numero_bc,
    email_from: from,
    email_subject: subject,
    email_body: body.substring(0, 1000),
    email_date: $input.item.json.date,
    has_pdf: pdfAttachments.length > 0,
    pdf_count: pdfAttachments.length,
    pdf_attachments: pdfAttachments,
    all_attachments: attachments
  },
  binary: binaryData  // ← AJOUT : Passer le binary
};

// Analyser le texte extrait du PDF
const text = $input.item.json.text || '';
const textLower = text.toLowerCase();

// Détecter si c'est une facture
const isFacture = 
  textLower.includes('facture') ||
  textLower.includes('invoice') ||
  textLower.includes('fact') ||
  textLower.includes('n°') && textLower.includes('date');

// Extraire numéro de facture
const numeroFactureRegex = /(facture|invoice|fact)[\s:n°#-]*(\d+[\/-]?\d*)/gi;
const numeroMatch = text.match(numeroFactureRegex);
const numero_facture = numeroMatch ? numeroMatch[0].replace(/[^0-9\/\-]/g, '') : null;

// Extraire date (formats: DD/MM/YYYY, DD-MM-YYYY, YYYY-MM-DD)
const dateRegex = /(\d{2}[\/\-]\d{2}[\/\-]\d{4})|(\d{4}[\/\-]\d{2}[\/\-]\d{2})/g;
const dateMatches = text.match(dateRegex);
const date_facture = dateMatches ? dateMatches[0] : null;

// Extraire montants (formats: 1234.56, 1 234,56, 1234,56)
const montantRegex = /(\d{1,3}(?:[\s,]\d{3})*(?:[.,]\d{2})?)(?=\s*(DH|MAD|EUR|€|dh))/g;
const montantMatches = text.match(montantRegex);

// Prendre le dernier montant (souvent le total TTC)
let montant_ttc = null;
if (montantMatches && montantMatches.length > 0) {
  const lastMontant = montantMatches[montantMatches.length - 1];
  // Normaliser: remplacer espaces et virgules par point
  montant_ttc = parseFloat(lastMontant.replace(/[\s]/g, '').replace(',', '.'));
}

// Extraire TVA si présente
const tvaRegex = /tva[\s:]*([\d.,]+)\s*%?/gi;
const tvaMatch = text.match(tvaRegex);
const taux_tva = tvaMatch ? parseFloat(tvaMatch[0].replace(/[^0-9.,]/g, '').replace(',', '.')) : 20.0;

// Score de confiance
let confidence_score = 0;
if (isFacture) confidence_score += 30;
if (numero_facture) confidence_score += 25;
if (date_facture) confidence_score += 25;
if (montant_ttc) confidence_score += 20;

return {
  is_facture: isFacture,
  numero_facture: numero_facture,
  date_facture: date_facture,
  montant_ttc: montant_ttc,
  taux_tva: taux_tva,
  confidence_score: confidence_score,
  texte_extrait: text.substring(0, 2000), // Limiter à 2000 caractères
  bc_id: $node["Merge Data"].json.bc_id,
  numero_bc: $node["Merge Data"].json.numero_bc,
  montant_bc: $node["Merge Data"].json.montant_ttc
};

const extractNode = $('Extract BC + PDFs').all();
const binaryData = extractNode[0].binary || {};

// Récupérer les infos PDF
const pdfAttachments = $json.pdf_attachments || [];

// Créer un item par PDF avec le binary
const items = []; 

for(const pdf of pdfAttachments) { 
      const pdfKey = pdf.key; 
          const pdfBinary = binaryData[pdfKey];  

          if (pdfBinary) { 
            items.push({ 
              json: { 
                bc_id: $json.bc_id, 
                numero_bc: $json.numero_bc, 
                montant_ttc: $json.montant_ttc, 
                montant_restant: $json.montant_restant, 
                email_from: $json.email_from, 
                pdf_filename: pdfBinary.fileName || pdf.filename, 
                pdf_size: pdfBinary.fileSize || 0, 
                pdf_key: pdfKey
              }, 
              binary: { 
                data: pdfBinary
              }
            }); 
          } 
        } 

return items;

// Merger résultats AI avec extraction basique
const basicExtraction = $node["Analyze PDF Content"].json;

let aiData = {};
try {
  // Parser réponse AI (enlever markdown si présent)
  let aiText = $input.item.json.response || '{}';
  aiText = aiText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  aiData = JSON.parse(aiText);
} catch (e) {
  console.log('AI parsing failed, using basic extraction');
  aiData = {};
}

// Utiliser AI si disponible, sinon extraction basique
return {
  bc_id: basicExtraction.bc_id,
  numero_bc: basicExtraction.numero_bc,
  numero_facture: aiData.numero_facture || basicExtraction.numero_facture,
  date_facture: aiData.date_facture || basicExtraction.date_facture,
  montant_ht: aiData.montant_ht || null,
  montant_tva: aiData.montant_tva || null,
  montant_ttc: aiData.montant_ttc || basicExtraction.montant_ttc,
  taux_tva: aiData.taux_tva || basicExtraction.taux_tva,
  est_partielle: aiData.est_partielle || false,
  est_facture: aiData.est_facture !== false, // Default true si AI confirme ou pas de réponse
  confidence_score: aiData.est_facture ? 95 : basicExtraction.confidence_score,
  texte_extrait: basicExtraction.texte_extrait,
  pdf_filename: basicExtraction.pdf_filename,
  pdf_size: basicExtraction.pdf_size,
  methode: aiData.est_facture ? 'AI' : 'Regex',
  email_from: $node["Merge Data"].json.email_from
};
